public class Solution {
    // set1 -> size n
    // set2 -> size m
    public static int[][] findintersection (int[][] set1, int[][] set2) {
        ArrayList<Integer> l3 = new ArrayList<>();
        ArrayList<Integer> r3 = new ArrayList<>();

        int l = 0;
        for (int i = 0; i < set1.length; i++) {
            while (set2[l][1] < set1[i][0]) l++;
            int j = l;
            while (j < set2.length && set2[j][0] <= set1[i][1]) {
                int maxl = set1[i][0] > set2[j][0] ? set1[i][0] : set2[j][0];
                int minr = set1[i][1] < set2[j][1] ? set1[i][1] : set2[j][1];
                if (maxl <= minr) {
                    l3.add(maxl);
                    r3.add(minr);
                }
                j++;
             }
        }

        int[][] ret = new int[l3.size()][2];
        for (int i = 0; i < l3.size(); i++) {
            ret[i][0] = l3.get(i);
            ret[i][1] = r3.get(i);
            System.out.println("[" + l3.get(i) + "," + r3.get(i) +"]");
        }
        return ret;
    }

